DROP TABLE IF EXISTS `products`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `products` (
  `product_id` varchar(50) NOT NULL,
  `product_name` varchar(255) NOT NULL,
  `brand_id` int(11) NOT NULL,
  `loves_count` int(11) DEFAULT NULL,
  `rating` decimal(3,2) DEFAULT NULL,
  `reviews` int(11) DEFAULT NULL,
  `size` varchar(255) DEFAULT NULL,
  `variation_type` varchar(100) DEFAULT NULL,
  `variation_value` varchar(255) DEFAULT NULL,
  `variation_desc` text DEFAULT NULL,
  `price_usd` decimal(10,2) DEFAULT NULL,
  `value_price_usd` decimal(10,2) DEFAULT NULL,
  `sale_price_usd` decimal(10,2) DEFAULT NULL,
  `limited_edition` tinyint(4) DEFAULT NULL,
  `is_new` tinyint(4) DEFAULT NULL,
  `online_only` tinyint(4) DEFAULT NULL,
  `out_of_stock` tinyint(4) DEFAULT NULL,
  `sephora_exclusive` tinyint(4) DEFAULT NULL,
  `child_count` int(11) DEFAULT NULL,
  `child_max_price` decimal(10,2) DEFAULT NULL,
  `child_min_price` decimal(10,2) DEFAULT NULL,
  PRIMARY KEY (`product_id`),
  KEY `idx_products_brand` (`brand_id`),
  KEY `idx_products_rating` (`rating`),
  KEY `idx_products_price` (`price_usd`),
  CONSTRAINT `1` FOREIGN KEY (`brand_id`) REFERENCES `brands` (`brand_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_uca1400_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

